import uuid, threading, time
from dataclasses import dataclass, field
from typing import Any

@dataclass
class Job:
    id: str
    status: str = "PENDING"    # PENDING | RUNNING | DONE | FAILED
    result: Any = None
    error: str | None = None
    started_at: float = field(default_factory=time.time)
    finished_at: float | None = None

_JOBS: dict[str, Job] = {}
_JOBS_LOCK = threading.Lock()

def _run_job(job_id: str, fn, args: tuple, kwargs: dict) -> None:
    with _JOBS_LOCK:
        _JOBS[job_id].status = "RUNNING"
    try:
        result = fn(*args, **kwargs)
        with _JOBS_LOCK:
            _JOBS[job_id].status = "DONE"
            _JOBS[job_id].result = result
            _JOBS[job_id].finished_at = time.time()
    except Exception as exc:
        with _JOBS_LOCK:
            _JOBS[job_id].status = "FAILED"
            _JOBS[job_id].error = str(exc)
            _JOBS[job_id].finished_at = time.time()

def start_job(fn, *args, **kwargs) -> str:
    job_id = str(uuid.uuid4())[:8]
    with _JOBS_LOCK:
        _JOBS[job_id] = Job(id=job_id)
    thread = threading.Thread(target=_run_job, args=(job_id, fn, args, kwargs), daemon=True)
    thread.start()
    return job_id

# --- Three tool functions exposed to Claude ---

def generate_report(dataset: str, format: str = "pdf") -> dict:
    """Start a long-running report generation job. Returns a job_id immediately."""
    job_id = start_job(_do_generate_report, dataset, format)
    return {
        "job_id": job_id,
        "status": "PENDING",
        "message": f"Report generation started. Poll get_report_status(job_id='{job_id}') to check progress.",
    }

def get_report_status(job_id: str) -> dict:
    """Check the status of a report generation job."""
    with _JOBS_LOCK:
        job = _JOBS.get(job_id)
    if job is None:
        return {"error": "NOT_FOUND", "message": f"No job with id: {job_id}"}
    elapsed = round(time.time() - job.started_at, 1)
    result = {"job_id": job_id, "status": job.status, "elapsed_seconds": elapsed}
    if job.status == "DONE":
        result["message"] = f"Report is ready. Call get_report_result(job_id='{job_id}') to fetch it."
    elif job.status == "FAILED":
        result["error_detail"] = job.error
    return result

def get_report_result(job_id: str) -> dict:
    """Retrieve the completed report. Call only after get_report_status returns DONE."""
    with _JOBS_LOCK:
        job = _JOBS.get(job_id)
    if job is None:
        return {"error": "NOT_FOUND", "message": f"No job: {job_id}"}
    if job.status != "DONE":
        return {"error": "NOT_READY",
                "message": f"Job is {job.status}. Poll get_report_status first.",
                "status": job.status}
    return {"job_id": job_id, "status": "DONE", "result": job.result}

def _do_generate_report(dataset: str, format: str) -> dict:
    time.sleep(5)   # simulate work
    return {"dataset": dataset, "format": format, "pages": 12, "url": f"/reports/{dataset}.{format}"}

import anthropic

tools = [
    {
        "name": "generate_report",
        "description": (
            "Start generating a report. Returns a job_id immediately — the report is NOT ready yet. "
            "After calling this, poll get_report_status(job_id) every few seconds until status is DONE, "
            "then call get_report_result(job_id) to retrieve the output."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "dataset": {"type": "string", "description": "Name of the dataset to report on"},
                "format": {"type": "string", "enum": ["pdf", "csv", "html"], "default": "pdf"},
            },
            "required": ["dataset"],
        },
    },
    {
        "name": "get_report_status",
        "description": (
            "Check the status of a report generation job. "
            "Returns status: PENDING | RUNNING | DONE | FAILED. "
            "Call this repeatedly until status is DONE before calling get_report_result."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "job_id": {"type": "string", "description": "Job ID returned by generate_report"},
            },
            "required": ["job_id"],
        },
    },
    {
        "name": "get_report_result",
        "description": (
            "Retrieve the completed report. ONLY call this after get_report_status returns status=DONE. "
            "Returns NOT_READY if the job has not finished."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "job_id": {"type": "string"},
            },
            "required": ["job_id"],
        },
    },
]

TOOL_DISPATCH = {
    "generate_report": generate_report,
    "get_report_status": get_report_status,
    "get_report_result": get_report_result,
}

client = anthropic.Anthropic()

def run_agent(user_message: str) -> str:
    messages = [{"role": "user", "content": user_message}]
    while True:
        resp = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            tools=tools,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            return next(b.text for b in resp.content if hasattr(b, "text"))
        messages.append({"role": "assistant", "content": resp.content})
        results = []
        for block in resp.content:
            if block.type == "tool_use":
                fn = TOOL_DISPATCH.get(block.name)
                result = fn(**block.input) if fn else {"error": "NOT_FOUND"}
                results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": str(result),
                })
        messages.append({"role": "user", "content": results})

MAX_JOB_SECONDS = 120   # 2-minute wall-clock limit

def get_report_status(job_id: str) -> dict:
    with _JOBS_LOCK:
        job = _JOBS.get(job_id)
    if job is None:
        return {"error": "NOT_FOUND", "message": f"No job: {job_id}"}

    elapsed = time.time() - job.started_at

    # Detect stuck jobs
    if job.status in ("PENDING", "RUNNING") and elapsed > MAX_JOB_SECONDS:
        with _JOBS_LOCK:
            _JOBS[job_id].status = "FAILED"
            _JOBS[job_id].error = f"Job exceeded {MAX_JOB_SECONDS} s wall-clock limit"
            _JOBS[job_id].finished_at = time.time()
        return {
            "job_id": job_id,
            "status": "FAILED",
            "error_detail": _JOBS[job_id].error,
            "retry_after_seconds": 30,
        }

    result = {"job_id": job_id, "status": job.status,
              "elapsed_seconds": round(elapsed, 1)}
    if job.status == "DONE":
        result["message"] = f"Ready. Call get_report_result('{job_id}')."
    elif job.status == "FAILED":
        result["error_detail"] = job.error
    elif job.status == "RUNNING":
        result["estimated_remaining_seconds"] = max(0, MAX_JOB_SECONDS - elapsed)
    return result
